import { useState, useContext, useEffect } from "react";
import { Container, Card, Form, Button, Alert, Image } from "react-bootstrap";
import axios from "axios";
import UserContext from "./context";

export default function Profile() {
    const { user, setUser } = useContext(UserContext);
    const [pin, setPin] = useState("");
    const [name, setName] = useState("");
    const [message, setMessage] = useState("");
    const [error, setError] = useState("");
    const [selectedFile, setSelectedFile] = useState(null);
    const [uploading, setUploading] = useState(false);

    useEffect(() => {
        if (user) {
            setPin(user.transactionPin || "");
            setName(user.name || "");
        }
    }, [user]);

    const handleUpdate = async (e) => {
        e.preventDefault();
        setMessage("");
        setError("");

        if (pin.length !== 4) {
            setError("PIN must be exactly 4 digits.");
            return;
        }

        try {
            const res = await axios.put("http://localhost:8080/api/users/profile-update", {
                name,
                transactionPin: pin
            });
            setUser(res.data.updatedUser);
            setMessage("Profile updated successfully!");
        } catch (err) {
            setError(err.response?.data?.message || "Failed to update profile.");
        }
    };

    const handleFileChange = (e) => {
        setSelectedFile(e.target.files[0]);
    };

    const handlePhotoUpload = async (e) => {
        e.preventDefault();
        if (!selectedFile) {
            setError("Please select a file first.");
            return;
        }

        const formData = new FormData();
        formData.append("photo", selectedFile);

        setUploading(true);
        setMessage("");
        setError("");

        try {
            const res = await axios.post("http://localhost:8080/api/users/upload-photo", formData, {
                headers: {
                    "Content-Type": "multipart/form-data"
                }
            });
            setUser(res.data.user);
            setMessage("Photo uploaded successfully!");
            setSelectedFile(null);
        } catch (err) {
            setError(err.response?.data?.message || "Failed to upload photo.");
        } finally {
            setUploading(false);
        }
    };

    if (!user) return <Container className="mt-5"><h3>Please login to view your profile.</h3></Container>;

    return (
        <Container className="mt-5 d-flex justify-content-center">
            <Card className="shadow-lg p-4 border-0" style={{ width: "550px", borderRadius: "15px", background: "linear-gradient(145deg, #ffffff, #f0f0f0)" }}>
                <Card.Header className="bg-dark text-white text-center" style={{ borderRadius: "10px 10px 0 0" }}>
                    <h3 className="mb-0">Your Profile</h3>
                </Card.Header>
                <Card.Body>
                    <div className="text-center mb-4">
                        <div className="position-relative d-inline-block">
                            <Image
                                src={user.profilePhoto ? `http://localhost:8080${user.profilePhoto}` : "https://via.placeholder.com/150"}
                                roundedCircle
                                className="mb-3 border border-dark shadow-sm"
                                style={{ width: "150px", height: "150px", objectFit: "cover" }}
                            />
                        </div>
                        <Form onSubmit={handlePhotoUpload}>
                            <Form.Group className="mb-2">
                                <Form.Control
                                    type="file"
                                    size="sm"
                                    onChange={handleFileChange}
                                    accept="image/*"
                                />
                            </Form.Group>
                            <Button
                                variant="outline-dark"
                                size="sm"
                                type="submit"
                                disabled={uploading || !selectedFile}
                                className="w-100"
                            >
                                {uploading ? "Uploading..." : "Upload Photo"}
                            </Button>
                        </Form>
                    </div>

                    {message && <Alert variant="success" className="text-center">{message}</Alert>}
                    {error && <Alert variant="danger" className="text-center">{error}</Alert>}

                    <Form onSubmit={handleUpdate}>
                        <Form.Group className="mb-3">
                            <Form.Label className="fw-bold">Name</Form.Label>
                            <Form.Control
                                type="text"
                                value={name}
                                onChange={(e) => setName(e.target.value)}
                                required
                                style={{ borderRadius: "8px" }}
                            />
                        </Form.Group>

                        <Form.Group className="mb-3">
                            <Form.Label className="fw-bold">Email Address</Form.Label>
                            <Form.Control type="email" value={user.email} disabled style={{ borderRadius: "8px", backgroundColor: "#e9ecef" }} />
                            <Form.Text className="text-muted">Email cannot be changed.</Form.Text>
                        </Form.Group>

                        <Form.Group className="mb-4">
                            <Form.Label className="fw-bold">4-Digit Transaction PIN</Form.Label>
                            <Form.Control
                                type="text"
                                maxLength="4"
                                value={pin}
                                onChange={(e) => setPin(e.target.value)}
                                required
                                style={{ borderRadius: "8px" }}
                            />
                            <Form.Text className="text-muted">Use this PIN for all deposits and withdrawals.</Form.Text>
                        </Form.Group>

                        <Button
                            variant="primary"
                            type="submit"
                            className="w-100 py-2 fw-bold shadow-sm"
                            style={{ borderRadius: "8px", background: "linear-gradient(45deg, #0d6efd, #0b5ed7)" }}
                        >
                            Update Profile Info
                        </Button>
                    </Form>
                </Card.Body>
            </Card>
        </Container>
    );
}
